import {ALERT} from './constants'

interface AiTableData<TActivity = any, TAnswer extends Record<string, any> = any> {
  submit?: boolean
  recordId: string
  data: KoboSubmissionFlat<TAnswer>[]
  activity: TActivity
  requestBody: ActivityInfoRequest
}

interface AiTableProps {
  data: AiTableData<AiType51aMonitoring.Type>[]
  columns: Seq<{
    key: string
    type: string
  }>
  period: Partial<Period>
  setPeriod: Dispatch<SetStateAction<Partial<Period>>>
  loading: boolean
}

